	return personaToGQL(p), nil
}

// PersonaUpdate is the resolver for the personaUpdate field.
func (r *mutationResolver) PersonaUpdate(ctx context.Context, name string, body string, projectID string) (*Persona, error) {
	writer := persona.NewProjectPersonaWriter(r.projectRoot(ctx, projectID))
	p, err := writer.Update(name, body)
	if err != nil {
		return nil, personaGraphQLError(err)
	}
	return personaToGQL(p), nil
}

// PersonaDelete is the resolver for the personaDelete field.

package graphql

import (
	"context"
	"time"

	"github.com/vektah/gqlparser/v2/gqlerror"
)

// ArtifactRegenerate is the resolver for the artifactRegenerate mutation.
//
// It looks up the artifact by ID and dispatches a server-side regeneration
// using the artifact's recorded generator metadata (generatedBy.runId and
// promptSummary). When the artifact has no generator metadata it returns a
// typed GraphQL error (extension code NO_GENERATOR_METADATA) so the UI can
// keep its Regenerate button disabled with an explanatory tooltip.
func (r *mutationResolver) ArtifactRegenerate(ctx context.Context, artifactID string) (*ArtifactRegenerateResult, error) {
	if r.workingDir(ctx) == "" {
		return nil, &gqlerror.Error{
			Message:    "working directory not configured",
			Extensions: map[string]any{"code": "NOT_CONFIGURED"},
		}
	}

	// Resolve the artifact across all known projects so the mutation works
	// even when the caller passed only the artifact ID. We re-use the same
	// collection logic used by the Artifact and Artifacts resolvers.
	artifact, err := findArtifactByID(r.Resolver, artifactID)
	if err != nil {
		return nil, err
	}
	if artifact == nil {
		return nil, &gqlerror.Error{
			Message:    "artifact not found",
			Extensions: map[string]any{"code": "ARTIFACT_NOT_FOUND"},
		}
	}
	if artifact.GeneratedBy == nil {
		return nil, &gqlerror.Error{
			Message: "artifact has no generator metadata; nothing to regenerate",
			Extensions: map[string]any{
				"code": "NO_GENERATOR_METADATA",
			},
		}
	}

	runID := newDispatchID("regen", artifactID)
	record := artifactRegenerateRecord{
		ID:            runID,
		ArtifactID:    artifactID,
		ArtifactPath:  artifact.Path,
		SourceRunID:   artifact.GeneratedBy.RunID,
		PromptSummary: artifact.GeneratedBy.PromptSummary,
		Status:        queuedPlaceholderState,
		CreatedAt:     time.Now().UTC(),
	}
	if err := writeJSONRecord(r.workingDir(ctx), "artifact-regenerations", runID, record); err != nil {
		return nil, err
	}

	return &ArtifactRegenerateResult{
		RunID:  runID,
		Status: queuedPlaceholderState,
	}, nil
}

type artifactRegenerateRecord struct {
	ID            string    `json:"id"`
	ArtifactID    string    `json:"artifact_id"`
	ArtifactPath  string    `json:"artifact_path"`
	SourceRunID   string    `json:"source_run_id"`
	PromptSummary string    `json:"prompt_summary"`
	Status        string    `json:"status"`
	CreatedAt     time.Time `json:"created_at"`
}

// findArtifactByID locates an artifact across the resolver's projects by ID.
// Falls back to scanning the resolver working directory when no project state
// is configured. Returns (nil, nil) when no artifact matches.
func findArtifactByID(r *Resolver, id string) (*Artifact, error) {
	roots := []string{}
	if r.State != nil {
		for _, p := range r.State.GetProjectSnapshots(false) {
			if p.Path != "" {
				roots = append(roots, p.Path)
			}
		}
	}
	// findArtifactByID has no ctx; fall back to the resolver's startup
	// WorkingDir for the unscoped no-State case. The State-based path above
	// remains the primary lookup, so this only matters when no projects
	// are registered.
	if len(roots) == 0 && r.WorkingDir != "" {
		roots = append(roots, r.WorkingDir)
	}
	for _, root := range roots {
		artifacts, err := collectArtifacts(root)
		if err != nil {
			continue
		}
		for _, a := range artifacts {
			if a.ID == id {
				return a, nil
			}
		}
	}
	return nil, nil
}

package graphql

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
	"gopkg.in/yaml.v3"
)

// repairRaceHook is a test seam invoked between the initial file read and the
// pre-write hash check. Production callers leave it nil; tests assign it to
// simulate a concurrent file modification so the stale-hash branch is
// exercised deterministically.
var repairRaceHook func()

// GraphRepairIssue applies a structured edit for an auto-repairable graph
// integrity issue, then re-validates the graph and returns the new issue list.
// The mutation refuses repairs whose target file changed during the call
// (concurrent repair) or whose target path escapes the project root.
func (r *mutationResolver) GraphRepairIssue(ctx context.Context, issueID string, strategy RepairStrategy) (*GraphRepairResult, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}
	if !strategy.IsValid() {
		return graphRepairFail(r.workingDir(ctx), fmt.Sprintf("unsupported repair strategy %q", strategy)), nil
	}

	graph, err := docgraph.BuildGraphWithConfig(r.workingDir(ctx))
	if err != nil {
		return nil, fmt.Errorf("building document graph: %w", err)
	}

	issue, ok := findIssueByStableID(graph.Issues, issueID)
	if !ok {
		return graphRepairFail(r.workingDir(ctx), "issue not found; the graph may have changed"), nil
	}

	if !strategySupportsKind(strategy, issue.Kind) {
		return graphRepairFail(r.workingDir(ctx), fmt.Sprintf("strategy %s cannot repair issue kind %q", strategy, issue.Kind)), nil
	}

	switch strategy {
	case RepairStrategyRemoveMissingDep:
		if err := repairRemoveMissingDep(graph, issue); err != nil {
			return graphRepairFail(r.workingDir(ctx), err.Error()), nil
		}
	case RepairStrategyApplySuggestedID:
		if err := repairApplySuggestedID(graph, issue); err != nil {
			return graphRepairFail(r.workingDir(ctx), err.Error()), nil
		}
	case RepairStrategyCleanPathMap:
		if err := repairCleanPathMap(r.workingDir(ctx), issue); err != nil {
			return graphRepairFail(r.workingDir(ctx), err.Error()), nil
		}
	default:
		return graphRepairFail(r.workingDir(ctx), fmt.Sprintf("unsupported repair strategy %q", strategy)), nil
	}

	rebuilt, err := docgraph.BuildGraphWithConfig(r.workingDir(ctx))
	if err != nil {
		return nil, fmt.Errorf("rebuilding graph after repair: %w", err)
	}
	return &GraphRepairResult{
		Success:   true,
		NewIssues: issuesToGQL(rebuilt.Issues),
	}, nil
}

func graphRepairFail(workingDir, msg string) *GraphRepairResult {
	out := &GraphRepairResult{
		Success:   false,
		NewIssues: []*GraphIssue{},
		Error:     &msg,
	}
	if workingDir != "" {
		if g, err := docgraph.BuildGraphWithConfig(workingDir); err == nil {
			out.NewIssues = issuesToGQL(g.Issues)
		}
	}
	return out
}

func findIssueByStableID(issues []docgraph.GraphIssue, id string) (docgraph.GraphIssue, bool) {
	for _, issue := range issues {
		if graphIssueStableID(issue) == id {
			return issue, true
		}
	}
	return docgraph.GraphIssue{}, false
}

func strategySupportsKind(strategy RepairStrategy, kind docgraph.IssueKind) bool {
	switch strategy {
	case RepairStrategyRemoveMissingDep:
		return kind == docgraph.IssueMissingDep
	case RepairStrategyApplySuggestedID:
		return kind == docgraph.IssueDuplicateID
	case RepairStrategyCleanPathMap:
		return kind == docgraph.IssueIDPathMissing || kind == docgraph.IssueIDPathMismatch
	}
	return false
}

// resolveProjectFile validates that relPath stays under root and returns its
// absolute, cleaned form. It rejects absolute paths and any path whose
// resolved form escapes root.
func resolveProjectFile(root, relPath string) (string, error) {
	if relPath == "" {
		return "", fmt.Errorf("path is empty")
	}
	clean := filepath.Clean(filepath.FromSlash(relPath))
	if filepath.IsAbs(clean) {
		return "", fmt.Errorf("path must be relative to project root")
	}
	if clean == ".." || strings.HasPrefix(clean, ".."+string(filepath.Separator)) {
		return "", fmt.Errorf("path escapes project root")
	}
	abs := filepath.Clean(filepath.Join(root, clean))
	rootAbs := filepath.Clean(root)
	rel, err := filepath.Rel(rootAbs, abs)
	if err != nil || rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) || filepath.IsAbs(rel) {
		return "", fmt.Errorf("path escapes project root")
	}
	return abs, nil
}

// readAndCheckStable reads the file at abs and confirms its content hash has
// not drifted from the snapshot captured at graph-build time. The repairRaceHook
// test seam fires in between to simulate a concurrent writer.
func readAndCheckStable(absPath, expectedHash string) (*yaml.Node, string, error) {
	currentHash, err := docgraph.HashDocumentFile(absPath)
	if err != nil {
		return nil, "", fmt.Errorf("hash file: %w", err)
	}
	if expectedHash != "" && currentHash != expectedHash {
		return nil, "", fmt.Errorf("file has changed since the issue was computed; refresh the page")
	}
	if repairRaceHook != nil {
		repairRaceHook()
	}
	rehash, err := docgraph.HashDocumentFile(absPath)
	if err != nil {
		return nil, "", fmt.Errorf("rehash file: %w", err)
	}
	if rehash != currentHash {
		return nil, "", fmt.Errorf("file changed during repair; aborting")
	}
	content, err := os.ReadFile(absPath)
	if err != nil {
		return nil, "", err
	}
	fm, body, err := docgraph.ParseFrontmatter(content)
	if err != nil {
		return nil, "", err
	}
	if !fm.HasFrontmatter || fm.Raw == nil {
		return nil, "", fmt.Errorf("file has no frontmatter")
	}
	return fm.Raw, body, nil
}

func repairRemoveMissingDep(graph *docgraph.Graph, issue docgraph.GraphIssue) error {
	if issue.Path == "" || issue.ID == "" {
		return fmt.Errorf("missing_dep issue is incomplete")
	}
	abs, err := resolveProjectFile(graph.RootDir, issue.Path)
	if err != nil {
		return err
	}
	declaringID, ok := graph.PathToID[issue.Path]
	if !ok {
		return fmt.Errorf("declaring document for %q is not in the graph", issue.Path)
	}
	doc := graph.Documents[declaringID]
	if doc == nil {
		return fmt.Errorf("declaring document for %q is not in the graph", issue.Path)
	}
	root, body, err := readAndCheckStable(abs, doc.ContentHash())
	if err != nil {
		return err
	}
	ns := findNamespaceNode(root)
	if ns == nil {
		return fmt.Errorf("frontmatter has no ddx/dun namespace")
	}
	depsNode := findChild(ns, "depends_on")
	if depsNode == nil || depsNode.Kind != yaml.SequenceNode {
		return fmt.Errorf("depends_on missing or not a sequence")
	}
	target := strings.TrimSpace(issue.ID)
	filtered := depsNode.Content[:0]
	removed := false
	for _, n := range depsNode.Content {
		if n.Kind == yaml.ScalarNode && strings.TrimSpace(n.Value) == target {
			removed = true
			continue
		}
		filtered = append(filtered, n)
	}
	if !removed {
		return fmt.Errorf("dependency %q not found in depends_on", target)
	}
	depsNode.Content = filtered
	if len(depsNode.Content) == 0 {
		removeChild(ns, "depends_on")
	}
	return writeFrontmatter(abs, root, body)
}

func repairApplySuggestedID(graph *docgraph.Graph, issue docgraph.GraphIssue) error {
	if issue.Path == "" || issue.ID == "" {
		return fmt.Errorf("duplicate_id issue is incomplete")
	}
	if issue.RelatedPath == "" {
		return fmt.Errorf("duplicate_id issue has no related path")
	}

	result, ok := resp.Result.(map[string]any)
	if !ok {
		t.Fatalf("expected result map, got %T", resp.Result)
	}
	contentAny, ok := result["content"].([]any)
	if !ok || len(contentAny) == 0 {
		t.Fatalf("expected content array, got %v", result["content"])
	}
	first, ok := contentAny[0].(map[string]any)
	if !ok {
		t.Fatalf("expected first content to be map")
	}
	text, _ = first["text"].(string)
	truncated, _ = first["truncated"].(bool)
	if ob, ok := first["original_bytes"].(float64); ok {
		originalBytes = int(ob)
	}
	return
}

func tail(s string, n int) string {
	if len(s) <= n {
		return s
	}
	return s[len(s)-n:]
}

// TestEvidencePrimitiveUsage is the static-analysis gate for FEAT-022 §10
// (Stage E1). It asserts that every mcpContent{Type:"text", ...}
// composite-literal construction in cli/internal/server/server.go
// either:
//
//   - is sourced from a Text field that originates from
//     evidence.ClampOutput in the immediately enclosing function, OR
//   - carries an //evidence:allow-unbounded line-comment annotation on
//     the literal itself.
//
// The package-level mcpText helper is the single mcpContent literal site
// in this file; every other caller must route through that helper. The
// test parses server.go, walks the AST, and rejects any unannotated
// non-helper literal so that future contributors cannot reintroduce
// unbounded text egress on the MCP surface.
func TestEvidencePrimitiveUsage(t *testing.T) {
	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, "server.go", nil, parser.ParseComments)
	if err != nil {
		t.Fatalf("parse server.go: %v", err)
	}

	// Build a map from line number → comment text for line-comments so
	// we can check the //evidence:allow-unbounded annotation that may
	// sit on the line before the literal.
	commentByLine := map[int]string{}
	for _, cg := range file.Comments {
		for _, c := range cg.List {
			line := fset.Position(c.Slash).Line
			commentByLine[line] = c.Text
		}
	}

	var problems []string
	ast.Inspect(file, func(n ast.Node) bool {
		cl, ok := n.(*ast.CompositeLit)
		if !ok {
			return true
		}
		ident, ok := cl.Type.(*ast.Ident)
		if !ok || ident.Name != "mcpContent" {
			return true
		}
		// Only consider literals whose Type field is "text".
		hasTextType := false
		for _, elt := range cl.Elts {
			kv, ok := elt.(*ast.KeyValueExpr)
			if !ok {
				continue
			}
			key, ok := kv.Key.(*ast.Ident)
			if !ok || key.Name != "Type" {
				continue
			}
			if bl, ok := kv.Value.(*ast.BasicLit); ok && bl.Value == `"text"` {
				hasTextType = true
			}
		}
		if !hasTextType {
			return true
		}
		// Allow when the line immediately before the literal carries
		// the annotation comment.
		startLine := fset.Position(cl.Lbrace).Line
		annotated := false
		for delta := 1; delta <= 3; delta++ {
			if c, ok := commentByLine[startLine-delta]; ok {
				if strings.Contains(c, "evidence:allow-unbounded") && strings.Contains(c, `reason="`) {
					annotated = true
					break
				}
			}
		}
		if !annotated {
			problems = append(problems, fset.Position(cl.Lbrace).String())
		}
		return true
	})

	if len(problems) > 0 {
		t.Fatalf("found unannotated mcpContent{Type:\"text\"} literal sites in server.go (each must use evidence.ClampOutput via the mcpText helper, or carry //evidence:allow-unbounded). Sites:\n  %s",
			strings.Join(problems, "\n  "))
	}
}

package server

// Lint test for ddx-15f7ee0b Fix A: every test file in this package (and
// adjacent directories that wire up ServerState) that constructs a server or
// loads a ServerState must point the state directory at an isolated location.
// Tests that skip this leak phantom project entries into the developer's real
// ~/.local/share/ddx/server-state.json.
//
// The check is intentionally conservative: a function that calls any of the
// "constructor" set below must also invoke at least one of the "isolation"
// set. Adding a new helper that internally isolates XDG_DATA_HOME is the
// preferred way to keep this passing.

import (
	"go/ast"
	"go/parser"
	"go/token"
	"io/fs"
	"path/filepath"
	"strings"
	"testing"
)

// constructorNames are function calls that build a server or directly load a
// ServerState. Any test that touches one of these must also pick up isolation.
// Entries without a "pkg." prefix match only package-local calls; entries like
// "server.New" match explicit cross-package qualified references.
var constructorNames = map[string]bool{
	"New":               true,
	"server.New":        true,
	"loadServerState":   true,
	"ListenAndServe":    true,
	"ListenAndServeTLS": true,
}

// isolationHelpers are helpers (defined in this package or adjacent test
// helpers) that set XDG_DATA_HOME before any server is created. A call to
// any of them satisfies the lint rule.
var isolationHelpers = map[string]bool{
	"setupTestDir":               true,
	"setupNodeTestDir":           true,
	"setupProcessMetricsTestDir": true,
	"setupDocTestDir":            true,
	"setupExecTestDir":           true,
	"setupGitTestDir":            true,
	"setupProjectWithBeads":      true,
	"setupBeadLookupFixture":     true,
	"BuildBeadFixture":           true,
}

// TestTestsIsolateStateDir walks the Go test files in the server package and
// perf sub-package, and asserts that every test (or benchmark) function that
// wires up a server also isolates XDG_DATA_HOME. See ddx-15f7ee0b Fix A.
func TestTestsIsolateStateDir(t *testing.T) {
	err := filepath.WalkDir(".", func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if d.IsDir() {
			switch d.Name() {
			case "frontend", "node_modules", ".svelte-kit", "build":
				return filepath.SkipDir
			default:
				return nil
			}
		}
		if strings.HasSuffix(d.Name(), "_test.go") {
			lintTestFile(t, path)
		}
		return nil
	})
	if err != nil {
		t.Fatalf("walk server tests: %v", err)
	}
}

func lintTestFile(t *testing.T, path string) {
	t.Helper()
	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, path, nil, parser.SkipObjectResolution)
	if err != nil {
		t.Fatalf("parse %s: %v", path, err)
	}

	// Skip the lint test file itself — it is allowed to reference constructor
	// names inside string maps without wiring up a server.
	if strings.HasSuffix(path, "/test_isolation_lint_test.go") {
		return
	}

	for _, decl := range file.Decls {
		fn, ok := decl.(*ast.FuncDecl)
		if !ok || fn.Body == nil {
			continue
		}
		// Only audit functions that could contain test code — Test*, Benchmark*,
		// or helpers used by such functions. For simplicity, audit all fns in
		// _test.go files. Helpers that unconditionally call setupTestDir etc.
		// will pass trivially.
		hasCtor := false
		hasIso := false
		ast.Inspect(fn.Body, func(n ast.Node) bool {
			call, ok := n.(*ast.CallExpr)
			if !ok {
				return true
			}
			name := callName(call.Fun)
			if constructorNames[name] {
				hasCtor = true
			}
			if isolationHelpers[name] {
				hasIso = true
			}
			// Detect raw XDG_DATA_HOME sets: any call with a first arg that is
			// the string literal "XDG_DATA_HOME".
			if name == "Setenv" || name == "t.Setenv" {
				// argList: check any arg is "XDG_DATA_HOME"
				for _, a := range call.Args {
					if lit, ok := a.(*ast.BasicLit); ok && lit.Kind == token.STRING {
						if strings.Trim(lit.Value, "`\"") == "XDG_DATA_HOME" {
							hasIso = true
						}
					}
				}
			}
			return true
		})

		if hasCtor && !hasIso {
			t.Errorf("%s: function %s constructs a server without isolating XDG_DATA_HOME — call setupTestDir/etc. or t.Setenv(\"XDG_DATA_HOME\", ...) before building the server (ddx-15f7ee0b Fix A)",
				path, fn.Name.Name)
		}
	}
}

// callName returns one of three things:
//   - For `Foo(...)`:         "Foo"
//   - For `pkg.Foo(...)`:     "pkg.Foo"
//   - For `t.Setenv(...)`:    "Setenv"  (receiver is a local identifier, not
//     a package — we only add the prefix when the
//     receiver looks like a package name, i.e.
//     lowercase and short; this is a heuristic.)
//
// Having qualified names lets the constructor list distinguish server.New
// from handler.New without false positives.
func callName(fn ast.Expr) string {
	switch v := fn.(type) {
	case *ast.Ident:
		return v.Name
	case *ast.SelectorExpr:
		if pkg, ok := v.X.(*ast.Ident); ok {
			// Heuristic: treat short lowercase identifiers as package names.
			// Receivers like `t`, `srv`, `w` fall through — we still want
			// Setenv to match for `t.Setenv(...)`. The Setenv match is
			// special-cased by the lint body; the selector branch here just
			// carries the package-qualified form when it looks right.
			if looksLikePackageName(pkg.Name) {
				return pkg.Name + "." + v.Sel.Name
			}
		}
		return v.Sel.Name
	}
	return ""
}

// looksLikePackageName is a heuristic for callName: longer-than-2 lowercase
// identifiers are treated as package-like (so "server.New" is distinguished
// from "srv.Shutdown"). Receivers like t, s, srv, b, tb return false.
func looksLikePackageName(s string) bool {
	if len(s) < 3 {
		return false
	}
	for _, r := range s {
		if r < 'a' || r > 'z' {
			return false
		}
	}
	// Reject common local-variable names that happen to be lowercase words.
	switch s {
	case "srv", "tb", "ctx", "err", "req", "res":
		return false
	}
	return true
}

// TestTestIsolationLintCatchesBadCase is a meta-test: it feeds the linter a
// synthetic "bad" file and asserts the linter flags it. Covers the
// "disallowed-pattern" arm of ddx-15f7ee0b Fix A.
func TestTestIsolationLintCatchesBadCase(t *testing.T) {
	badSource := `package server

import "testing"

func TestBadlyIsolatedExample(t *testing.T) {
	srv := New(":0", "/tmp/ignored")
	_ = srv
}
`
	goodSource := `package server

import "testing"

func TestProperlyIsolatedExample(t *testing.T) {
	t.Setenv("XDG_DATA_HOME", t.TempDir())
	srv := New(":0", "/tmp/ignored")
	_ = srv
}
`
	if got := lintSourceString(badSource); got == nil {
		t.Error("expected bad source to be flagged by lint, got nil")
	}
	if got := lintSourceString(goodSource); got != nil {
		t.Errorf("expected good source to pass lint, got error: %v", got)
	}
}

// lintSourceString runs the same AST walk on an in-memory source string and
// returns a non-nil error if the lint would have failed. Used by the meta-test.
func lintSourceString(src string) error {
	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, "synthetic.go", src, parser.SkipObjectResolution)
	if err != nil {
		return err
	}
	for _, decl := range file.Decls {
		fn, ok := decl.(*ast.FuncDecl)
		if !ok || fn.Body == nil {
			continue
		}
		hasCtor := false
		hasIso := false
		ast.Inspect(fn.Body, func(n ast.Node) bool {
			call, ok := n.(*ast.CallExpr)
			if !ok {
				return true
			}
			name := callName(call.Fun)
			if constructorNames[name] {
				hasCtor = true
			}
			if isolationHelpers[name] {
				hasIso = true
			}
			if name == "Setenv" {
				for _, a := range call.Args {
					if lit, ok := a.(*ast.BasicLit); ok && lit.Kind == token.STRING {
						if strings.Trim(lit.Value, "`\"") == "XDG_DATA_HOME" {
							hasIso = true
						}
					}
				}
			}
			return true
		})
		if hasCtor && !hasIso {
			return &lintErr{msg: fn.Name.Name + " constructs server without isolation"}
		}
	}
	return nil
}

type lintErr struct{ msg string }

func (e *lintErr) Error() string { return e.msg }

