108	func lintMutationConformance(schemaSrc, serverSrc string, resolverSources map[string]string) error {
109		schema := gqlparser.MustLoadSchema(&gqlast.Source{Name: "schema.graphql", Input: schemaSrc})
110		var problems []string
111	
112		if err := checkGraphQLRouteGate(serverSrc); err != nil {
113			problems = append(problems, err.Error())
114		}
115	
116		resolvers, err := parseMutationResolvers(resolverSources)
117		if err != nil {
118			problems = append(problems, err.Error())
119		}
120	
121		if schema.Mutation == nil {
122			problems = append(problems, "schema.graphql does not define a Mutation type")
123		} else {
124			for _, field := range schema.Mutation.Fields {
125				name := field.Name
126				if !strings.HasPrefix(name, "operatorPrompt") {
127					continue
128				}
129				rule, ok := promptMutationRules[name]
130				if !ok {
131					problems = append(problems, fmt.Sprintf("mutation %s is prompt-like but not allowlisted; add an explicit rule before shipping", name))
132					continue
133				}
134				fn, ok := resolvers[rule.resolverName]
135				if !ok {
136					problems = append(problems, fmt.Sprintf("mutation %s missing resolver %s in parsed source", name, rule.resolverName))
137					continue
138				}
139				if err := checkResolverGate(name, fn, rule); err != nil {
140					problems = append(problems, err.Error())
141				}
142			}
143		}
144	
145		if len(problems) > 0 {
146			return errors.New(strings.Join(problems, "\n"))
147		}
148		return nil
149	}
