151	func checkGraphQLRouteGate(serverSrc string) error {
152		fset := token.NewFileSet()
153		file, err := parser.ParseFile(fset, "server.go", serverSrc, parser.SkipObjectResolution)
154		if err != nil {
155			return fmt.Errorf("parse server.go: %w", err)
156		}
157	
158		var hasPost, hasGet, hasRequireTrusted bool
159		goast.Inspect(file, func(n goast.Node) bool {
160			call, ok := n.(*goast.CallExpr)
161			if !ok {
162				return true
163			}
164			if callName(call.Fun) == "requireTrusted" {
165				hasRequireTrusted = true
166			}
167			if callName(call.Fun) != "trusted" || len(call.Args) == 0 {
168				return true
169			}
170			lit, ok := call.Args[0].(*goast.BasicLit)
171			if !ok || lit.Kind != token.STRING {
172				return true
173			}
174			switch strings.Trim(lit.Value, "`\"") {
175			case "POST /graphql":
176				hasPost = true
177			case "GET /graphql":
178				hasGet = true
179			}
180			return true
181		})
182		if !hasRequireTrusted {
183			return fmt.Errorf("server.go must keep trusted() delegating to requireTrusted(handler)")
184		}
185		if !hasPost || !hasGet {
186			return fmt.Errorf("server.go must register /graphql through trusted() for both GET and POST (have GET=%t POST=%t)", hasGet, hasPost)
187		}
188		return nil
189	}
