191	func parseMutationResolvers(sources map[string]string) (map[string]resolverDecl, error) {
192		out := make(map[string]resolverDecl)
193		for path, src := range sources {
194			fset := token.NewFileSet()
195			file, err := parser.ParseFile(fset, path, src, parser.SkipObjectResolution)
196			if err != nil {
197				return nil, fmt.Errorf("parse %s: %w", path, err)
198			}
199			for _, decl := range file.Decls {
200				fn, ok := decl.(*goast.FuncDecl)
201				if !ok || fn.Body == nil || fn.Recv == nil || len(fn.Recv.List) == 0 {
202					continue
203				}
204				if !isMutationResolver(fn.Recv.List[0].Type) {
205					continue
206				}
207				out[fn.Name.Name] = resolverDecl{file: path, fn: fn}
208			}
209		}
210		return out, nil
211	}
212	
213	func isMutationResolver(expr goast.Expr) bool {
214		switch v := expr.(type) {
215		case *goast.StarExpr:
216			if ident, ok := v.X.(*goast.Ident); ok {
217				return ident.Name == "mutationResolver"
218			}
219		case *goast.Ident:
220			return v.Name == "mutationResolver"
221		}
222		return false
223	}
224	
225	func checkResolverGate(mutation string, decl resolverDecl, rule promptMutationRule) error {
226		calls := map[string]bool{}
227		idents := map[string]bool{}
228		goast.Inspect(decl.fn.Body, func(n goast.Node) bool {
229			switch v := n.(type) {
230			case *goast.CallExpr:
231				calls[callName(v.Fun)] = true
232			case *goast.Ident:
233				idents[v.Name] = true
234			}
235			return true
236		})
237	
238		var missing []string
239		for _, name := range rule.requiredCallNames {
240			if !calls[name] {
241				missing = append(missing, "call "+name)
242			}
243		}
244		for _, name := range rule.requiredIdents {
245			if !idents[name] {
246				missing = append(missing, "identifier "+name)
247			}
248		}
249		if len(missing) > 0 {
250			return fmt.Errorf("%s in %s missing %s", mutation, decl.file, strings.Join(missing, ", "))
251		}
252		return nil
253	}
