255	func loadMutationResolvers(dir string) (map[string]string, error) {
256		files, err := filepath.Glob(filepath.Join(dir, "resolver_*.go"))
257		if err != nil {
258			return nil, err
259		}
260		sources := make(map[string]string, len(files))
